// ColorExtraction: sample N colors from input, display as palette swatches
var src = inputs[0];
if (src == null) return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0f, 0f, 0f, 1f);
var count = Math.Clamp(GetInt(parameters, "colorCount", 8), 1, 32);
var size = context.TileSize;
var seed = GetInt(parameters, "seed", context.Seed);
var result = new PixelBuffer(size, size);
// Sample colors at seed-driven random positions for varied results
var colors = new (float r, float g, float b)[count];
var totalPixels = src.Width * src.Height;
for (var i = 0; i < count; i++)
{
    // Use hash to pick a deterministic random pixel per seed
    var idx = (int)(HashToUnit(i, 0, seed) * totalPixels) % totalPixels;
    var sx = idx % src.Width;
    var sy = idx / src.Width;
    var (r, g, b, _) = src.GetPixel(sx, sy);
    colors[i] = (r, g, b);
}
// Draw swatches
var swatchW = size / count;
result.ParallelForEachPixel((x, y) =>
{
    var idx = Math.Min(x / Math.Max(1, swatchW), count - 1);
    var (r, g, b) = colors[idx];
    result.SetPixel(x, y, r, g, b, 1f);
});
return result;
}
